const incoming = $json.body || $json;

function getSeverity(e) {
  const raw = e.detail?.severity ?? e.detail?.findings?.[0]?.Severity?.Normalized ?? null;
  if (raw == null) return { label: 'UNKNOWN', numeric: null };
  if (raw >= 7) return { label: 'HIGH', numeric: raw };
  if (raw >= 4) return { label: 'MEDIUM', numeric: raw };
  return { label: 'LOW', numeric: raw };
}

function getResource(e) {
  const r = e.detail?.resource || {};
  return {
    type: e.detail?.type || null,
    region: e.region || null,
    accountId: e.account || e.detail?.accountId || null,
    resourceType: r.resourceType || null,
    accessKeyId: r.accessKeyDetails?.accessKeyId || null,
    userName: r.accessKeyDetails?.userName || null,
    instanceId: r.instanceDetails?.instanceId || null
  };
}

const severity = getSeverity(incoming);
const resource = getResource(incoming);

return [{
  json: {
    source: incoming.source,
    detailType: incoming['detail-type'],
    title: incoming.detail?.title || incoming['detail-type'],
    description: incoming.detail?.description || null,
    severity,
    resource,
    receivedAt: new Date().toISOString(),
    raw: incoming
  }
}];
